// src/pages/vendor/VendorPortal.jsx
import React, { useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import { KPI } from '../../components/UI';
import ComplaintCard from '../../components/ComplaintCard';
import { CLEANERS } from '../../data/mockData';

export default function VendorPortal() {
  const { complaints, updateComplaint } = useApp();
  const [activeTab, setActiveTab] = useState('TASKS');
  const [modalTask, setModalTask] = useState(null);

  // Vendor Scope Configuration Mapping
  const myVendorId = 'v1'; 
  const currentAssignedTasks = complaints.filter(c => c.vendor?.id === myVendorId || (!c.vendor && ['s1', 's2'].includes(c.station?.id)));

  const kpiNew = currentAssignedTasks.filter(c => c.status === 'NEW').length;
  const kpiActive = currentAssignedTasks.filter(c => ['ACCEPTED', 'IN_PROGRESS'].includes(c.status)).length;
  const kpiDone = currentAssignedTasks.filter(c => c.status === 'COMPLETED').length;

  const handleAccept = (id) => updateComplaint(id, { status: 'ACCEPTED', cleanerStatus: 'ASSIGNED' });
  const handleAssignClick = (task) => setModalTask(task);
  
  const executeAssignment = (cleaner) => {
    if (!modalTask) return;
    updateComplaint(modalTask.id, {
      assignedTo: cleaner.name,
      status: 'IN_PROGRESS',
      cleanerStatus: 'CLEANING',
      vendor: { id: myVendorId, name: 'CleanRail Pvt Ltd' }
    });
    setModalTask(null);
  };

  const navItems = [
    { key: 'TASKS', label: 'Zonal Deployments', icon: '📋', count: kpiNew },
    { key: 'CREW', label: 'Ground Squad', icon: '👥', count: 0 }
  ];

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#F7F9FC', overflow: 'hidden', fontFamily: 'sans-serif' }}>
      <Sidebar 
        title="Zonal Control Desk" subtitle="CleanRail Contractor Panel" 
        navItems={navItems} activeTab={activeTab} onTabChange={setActiveTab}
        footerUser={{ name: 'R.K. Meena', role: 'Operations Head', initials: 'RM', avatarColor: '#004D40' }}
      />

      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden', padding: 20 }}>
        {activeTab === 'TASKS' ? (
          <>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 14, marginBottom: 20 }}>
              <KPI title="NEW INCOMING UNTOUCHED" value={kpiNew} color="#E65100" />
              <KPI title="ACTIVE SWEEPS" value={kpiActive} color="#1565C0" />
              <KPI title="ARCHIVED RESOLVED" value={kpiDone} color="#2E7D32" />
            </div>

            <div style={{ flex: 1, overflowY: 'auto', display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: 16, alignItems: 'start' }}>
              {currentAssignedTasks.map(c => (
                <ComplaintCard key={c.id} complaint={c} onAccept={handleAccept} onAssign={handleAssignClick} />
              ))}
            </div>
          </>
        ) : (
          <div>
            <h3 style={{ margin: '0 0 12px 0' }}>Crew Ground Registry</h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {CLEANERS.map(c => (
                <div key={c.id} style={{ background: '#fff', padding: 14, borderRadius: 10, border: '1px solid #DDE3E9', display: 'flex', justifyContent: 'space-between' }}>
                  <div><strong>{c.name}</strong> — <span style={{ fontSize: 12, color: '#546E7A' }}>{c.area}</span></div>
                  <span style={{ fontSize: 11, color: c.active ? '#2E7D32' : '#B71C1C', fontWeight: 'bold' }}>{c.active ? '● STATION DUTY' : '○ OFF-DUTY'}</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {modalTask && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 10000 }}>
          <div style={{ background: '#fff', padding: 20, borderRadius: 12, width: 340 }}>
            <h4 style={{ margin: '0 0 12px 0' }}>Dispatch Field Operator</h4>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {CLEANERS.filter(c => c.active).map(cleaner => (
                <button key={cleaner.id} onClick={() => executeAssignment(cleaner)} style={{ width: '100%', padding: 10, background: '#F7F9FC', border: '1px solid #DDE3E9', borderRadius: 8, cursor: 'pointer', textAlign: 'left', fontWeight: 600 }}>
                  🏃‍♂️ {cleaner.name} ({cleaner.area})
                </button>
              ))}
              <button onClick={() => setModalTask(null)} style={{ marginTop: 8, border: 'none', background: 'transparent', color: '#7A8FA6', cursor: 'pointer', fontWeight: 'bold', width: '100%' }}>Abort Allocation</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
